local xml = require "lxxml"
local cjson = require "cjson"

local function parse_soap_request()
    local request_body = ngx.req.get_body_data()
    if not request_body then
        ngx.status = 400
        ngx.say("Missing request body")
        ngx.exit(400)
        return
    end
    
    local parser = xml.new()
    parser:setEntityResolver(function(name)
        return ""
    end)
    
    local doc, err = parser:parse(request_body)
    if not doc then
        ngx.status = 400
        ngx.say("Invalid XML: " .. err)
        ngx.exit(400)
        return
    end
    
    local soap_env = doc:getRootElement()
    if not soap_env then
        ngx.status = 400
        ngx.say("Invalid SOAP envelope")
        ngx.exit(400)
        return
    end
    
    local soap_body = soap_env:getChild("Body")
    if not soap_body then
        ngx.status = 400
        ngx.say("Missing SOAP body")
        ngx.exit(400)
        return
    end
    
    local method_element = soap_body:getFirstChild()
    if not method_element then
        ngx.status = 400
        ngx.say("Missing method in SOAP body")
        ngx.exit(400)
        return
    end
    
    local method_name = method_element:name()
    local method_data = {}
    
    local children = method_element:getChildren()
    for i, child in ipairs(children) do
        method_data[child:name()] = child:getText()
    end
    
    return {
        method = method_name,
        data = method_data
    }
end

local function process_soap_request()
    local parsed_data = parse_soap_request()
    if not parsed_data then
        return
    end
    
